  ('sun-city-south', 'Sun City South', 'Yellow', 'Yellow', 'F', 68.5, 111, 5195, 'https://cms.suncityaz.org/media/sffcoe52/sun-city-south-118113.pdf'),
  ('sun-city-lakes-west', 'Sun City Lakes West', 'Blue', 'Blue', 'M', 68.8, 117, 6195, 'https://cms.suncityaz.org/media/kgrp1vqd/sun-city-az-lakes-west-123.pdf'),
  ('sun-city-lakes-west', 'Sun City Lakes West', 'White', 'White', 'M', 67.8, 112, 5944, 'https://cms.suncityaz.org/media/kgrp1vqd/sun-city-az-lakes-west-123.pdf'),
  ('sun-city-lakes-west', 'Sun City Lakes West', 'White', 'White', 'F', 73.2, 121, 5944, 'https://cms.suncityaz.org/media/kgrp1vqd/sun-city-az-lakes-west-123.pdf'),
  ('sun-city-lakes-west', 'Sun City Lakes West', 'Red', 'Red', 'M', 66.0, 107, 5620, 'https://cms.suncityaz.org/media/kgrp1vqd/sun-city-az-lakes-west-123.pdf'),
  ('sun-city-lakes-west', 'Sun City Lakes West', 'Red', 'Red', 'F', 71.0, 114, 5620, 'https://cms.suncityaz.org/media/kgrp1vqd/sun-city-az-lakes-west-123.pdf'),
  ('sun-city-lakes-west', 'Sun City Lakes West', 'Yellow', 'Yellow', 'M', 62.0, 97, 4696, 'https://cms.suncityaz.org/media/kgrp1vqd/sun-city-az-lakes-west-123.pdf'),
  ('sun-city-lakes-west', 'Sun City Lakes West', 'Yellow', 'Yellow', 'F', 66.3, 105, 4696, 'https://cms.suncityaz.org/media/kgrp1vqd/sun-city-az-lakes-west-123.pdf'),
  ('sun-city-lakes-east', 'Sun City Lakes East', 'White', 'White', 'M', 56.8, 84, 3310, 'https://cms.suncityaz.org/media/1cgj5pfg/sun-city-lakes-golf-club-east-course-13595.pdf'),
  ('sun-city-lakes-east', 'Sun City Lakes East', 'Red', 'Red', 'M', 55.7, 80, 2914, 'https://cms.suncityaz.org/media/1cgj5pfg/sun-city-lakes-golf-club-east-course-13595.pdf')
), upsert_courses as (
  insert into public.saved_courses (source_provider, source_course_id, name, normalized_name, city, state, updated_at)
  select 'manual_seed', course_key, course_name, course_key, city, state, now() from course_seed
  on conflict (normalized_name, city, state) do update set name=excluded.name, source_provider=excluded.source_provider, source_course_id=excluded.source_course_id, updated_at=now()
  returning id, normalized_name, city, state
), all_courses as (
  select c.id, s.* from course_seed s join public.saved_courses c on c.normalized_name=s.course_key and c.city is not distinct from s.city and c.state is not distinct from s.state
), upsert_tees as (
  insert into public.saved_course_tees (course_key, course_name, tee_name, tee_color, gender, course_rating, slope_rating, total_yards, source_url, updated_at)
  select course_key, course_name, tee_name, tee_color, gender, course_rating, slope_rating, total_yards, source_url, now() from tee_seed
  on conflict (course_key, tee_name, gender) do update set course_name=excluded.course_name, tee_color=excluded.tee_color, course_rating=excluded.course_rating, slope_rating=excluded.slope_rating, total_yards=excluded.total_yards, source_url=excluded.source_url, updated_at=now()
)
insert into public.saved_course_holes (saved_course_id, hole_number, par, handicap_index, updated_at)
select c.id, hole_number, c.pars[hole_number], c.hcps[hole_number], now() from all_courses c cross join generate_series(1,18) as hole_number
on conflict (saved_course_id, hole_number) do update set par=excluded.par, handicap_index=excluded.handicap_index, updated_at=now();

select (select count(*) from public.saved_courses where source_provider='manual_seed') as seeded_courses, (select count(*) from public.saved_course_holes h join public.saved_courses c on c.id=h.saved_course_id where c.source_provider='manual_seed') as seeded_holes, (select count(*) from public.saved_course_tees where course_key in (select normalized_name from public.saved_courses where source_provider='manual_seed')) as seeded_tees;
